/**
 * evolutions.ts — static Gen 1 + Gen 2 Pokémon evolution data
 *
 * Auto-generated by scrape-evolutions.mjs — do not edit by hand.
 * Re-run the script if evolution data needs updating.
 *
 * Each entry describes one evolution step: a (from → to) pair with
 * a typed condition explaining what triggers the evolution.
 *
 * ──────────────────────────────────────────────────────────────────
 * DATA STRUCTURE DESIGN NOTES
 * ──────────────────────────────────────────────────────────────────
 *
 * EvolutionCondition is a discriminated union on the `trigger` field.
 * This lets TypeScript narrow the type safely and lets your app filter
 * to only the triggers it supports:
 *
 *   const levelUps = EVOLUTIONS.filter(
 *     (e): e is EvolutionStep<LevelUpCondition> =>
 *       e.condition.trigger === "level-up"
 *   );
 *
 * Current trigger types in Gen 1+2:
 *
 *   "level-up"   — Pokémon reaches a specific level.
 *                  condition.level holds the required level.
 *                  This is your current app scope.
 *
 *   "trade"      — Pokémon is traded.
 *                  condition.heldItem is non-null when a held item is
 *                  required (e.g. Onix + Metal Coat → Steelix).
 *
 *   "use-item"   — A specific item is used on the Pokémon.
 *                  condition.item names the stone / item.
 *                  (e.g. "water-stone", "fire-stone", "moon-stone")
 *
 *   "happiness"  — Pokémon has high friendship (≥220).
 *                  condition.timeOfDay is "day", "night", or null.
 *                  (e.g. Eevee → Espeon is "day", → Umbreon is "night")
 *
 *   "other"      — Edge cases (Tyrogue stat check, etc.)
 *                  condition.note is a human-readable description.
 */

// ─── Types ────────────────────────────────────────────────────────────────────

export type LevelUpCondition = {
  trigger: "level-up";
  /** Minimum level required to evolve. */
  level: number;
};

export type TradeCondition = {
  trigger: "trade";
  /** Item that must be held during trade, or null if no item needed. */
  heldItem: string | null;
};

export type UseItemCondition = {
  trigger: "use-item";
  /** Name of the evolution item (e.g. "water-stone", "moon-stone"). */
  item: string;
};

export type HappinessCondition = {
  trigger: "happiness";
  /** Time of day restriction, or null if any time works. */
  timeOfDay: "day" | "night" | null;
};

export type OtherCondition = {
  trigger: "other";
  /** Human-readable description of the special requirement. */
  note: string;
};

/** Discriminated union — narrow via `condition.trigger`. */
export type EvolutionCondition =
  | LevelUpCondition
  | TradeCondition
  | UseItemCondition
  | HappinessCondition
  | OtherCondition;

export type EvolutionStep<C extends EvolutionCondition = EvolutionCondition> = {
  /** National Pokédex ID of the pre-evolution. */
  fromId: number;
  fromName: string;
  /** National Pokédex ID of the evolved form. */
  toId: number;
  toName: string;
  /** Typed condition describing what triggers this evolution. */
  condition: C;
};

