// ─── Helpers ──────────────────────────────────────────────────────────────────

/**
 * Returns the evolution step for a given Pokémon ID, if one exists.
 * Useful for your current level-up scope:
 *
 *   const step = getEvolution(pokemonId);
 *   if (step?.condition.trigger === "level-up" && currentLevel >= step.condition.level) {
 *     evolve(pokemon, step.toId);
 *   }
 */
export function getEvolution(fromId: number): EvolutionStep | undefined {
  return EVOLUTIONS.find((e) => e.fromId === fromId);
}

/**
 * Returns ALL evolution steps for a Pokémon ID.
 * Needed for branching evolutions like Eevee (8 possible evolutions).
 */
export function getAllEvolutions(fromId: number): EvolutionStep[] {
  return EVOLUTIONS.filter((e) => e.fromId === fromId);
}

/**
 * Returns only level-up evolutions — your current app scope.
 * TypeScript will narrow condition to LevelUpCondition automatically.
 */
export function getLevelUpEvolutions(): EvolutionStep<LevelUpCondition>[] {
  return EVOLUTIONS.filter(
    (e): e is EvolutionStep<LevelUpCondition> =>
      e.condition.trigger === "level-up",
  );
}
